import {
  NavigationArea,
  ShellFrame,
  ShellHeaderFrame,
  ShellScrollableContent,
  ShellTabBar,
  type ShellTab,
} from '@medalsocial/meda'
import type { ComponentProps, ReactNode } from 'react'

type MedaShellProps = {
  headerLeft: ReactNode
  headerRight?: ReactNode
  navigation: ReactNode
  tabs?: ShellTab[]
  activeTab?: string
  renderTabLink: ComponentProps<typeof ShellTabBar>['renderLink']
  children: ReactNode
}

export function MedaShell({
  headerLeft,
  headerRight,
  navigation,
  tabs = [],
  activeTab,
  renderTabLink,
  children,
}: MedaShellProps) {
  return (
    <ShellFrame
      header={
        <ShellHeaderFrame
          left={headerLeft}
          center={
            tabs.length > 0 ? (
              <ShellTabBar
                tabs={tabs}
                activeTab={activeTab}
                ariaLabel="Workspace tabs"
                renderLink={renderTabLink}
              />
            ) : null
          }
          right={headerRight}
        />
      }
      navigation={<NavigationArea>{navigation}</NavigationArea>}
      content={
        <ShellScrollableContent layout="workspace" maxWidth={1120}>
          {children}
        </ShellScrollableContent>
      }
    />
  )
}
